const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

async function runPipeline() {
  try {
    console.log('Starting CI/CD pipeline...');
    
    // Install dependencies
    console.log('Installing dependencies...');
    execSync('npm ci --prefer-offline --no-audit', { stdio: 'inherit' });
    
    // Run tests
    console.log('Running tests...');
    execSync('npm test', { stdio: 'inherit' });
    
    // Build application
    console.log('Building application...');
    execSync('npm run build', { stdio: 'inherit' });
    
    // Generate SBOM
    console.log('Generating SBOM...');
    const sbomPath = path.join(process.cwd(), 'sbom.json');
    const sbomContent = {
      version: '1.0',
      components: [],
      timestamp: new Date().toISOString()
    };
    
    // Add dependencies to SBOM
    const packageLock = JSON.parse(fs.readFileSync('package-lock.json', 'utf8'));
    const dependencies = Object.keys(packageLock.dependencies || {});
    
    dependencies.forEach(dep => {
      const version = packageLock.dependencies[dep]?.version;
      if (version) {
        sbomContent.components.push({
          name: dep,
          version: version,
          type: 'library'
        });
      }
    });
    
    fs.writeFileSync(sbomPath, JSON.stringify(sbomContent, null, 2));
    console.log('SBOM generated successfully');
    
    // Deploy to production
    console.log('Deploying to production...');
    execSync('npm run deploy', { stdio: 'inherit' });
    
    console.log('Pipeline completed successfully');
  } catch (error) {
    console.error('Pipeline failed:', error.message);
    process.exit(1);
  }
}

runPipeline();